#!/bin/bash
set -e
echo "==> OurSunnah: Seeding 5 premium Islamic history/tradition blog posts"

if [ ! -f "pnpm-workspace.yaml" ]; then
  echo "ERROR: Run this script from the OurSunnah monorepo root (where pnpm-workspace.yaml lives)."
  exit 1
fi

SEED_FILE="packages/database/prisma/seed.ts"

if [ ! -f "$SEED_FILE" ]; then
  echo "ERROR: $SEED_FILE not found. Is this the right repo?"
  exit 1
fi

mkdir -p packages/database/prisma/seeds

echo "  - writing packages/database/prisma/seeds/journal-seed.ts (5 posts)"
echo "" | base64 -d > packages/database/prisma/seeds/journal-seed.ts

if grep -q "seedJournalPosts" "$SEED_FILE"; then
  echo "  - $SEED_FILE already wired for journal seeding, skipping overwrite"
else
  echo "  - backing up $SEED_FILE -> ${SEED_FILE}.bak"
  cp "$SEED_FILE" "${SEED_FILE}.bak"
  echo "  - writing $SEED_FILE (adds seedJournalPosts, preserves all existing seed logic)"
  echo "" | base64 -d > "$SEED_FILE"
fi

echo ""
echo "==> Done."
echo ""
echo "==> Run seed:"
echo "    pnpm --filter @our-sunnah/database seed"
echo ""
echo "==> Posts included:"
echo "    1. The Miswak: A Fourteen-Century Habit Modern Dentistry Is Catching Up To"
echo "    2. Attar: How the Islamic World Perfected the Art of Scent"
echo "    3. Bayt al-Hikmah: Inside the House of Wisdom That Lit the Dark Ages"
echo "    4. The Geometry of Faith: Why Islamic Art Never Drew a Face"
echo "    5. The Fanous: How a Tenth-Century Lantern Became the Symbol of Ramadan"
echo ""
echo "    All featured images are demo Unsplash links - swap them out via"
echo "    PATCH /journal/:id once real Cloudinary uploads are ready."
echo ""
echo "    NOTE: if seed.ts was overwritten, your original is saved at ${SEED_FILE}.bak"
echo "    Diff it if you had local changes: diff packages/database/prisma/seed.ts.bak packages/database/prisma/seed.ts"
